import sys

def solve():
    data = sys.stdin.read().split()
    n, m = int(data[0]), int(data[1])
    a = data[2]
    b = data[3]

    W = n - m + 1
    INF = float('inf')

    # cost to make window i match b
    cost_match = [sum(1 for j in range(m) if a[i+j] != b[j]) for i in range(W)]

    # Precompute: given last match at position p, next match at position i,
    # what is the incremental cost and is it feasible?
    # Also need cost to ensure windows between p and i don't match.

    # For each pair (prev_match, cur_match), precompute transition cost
    # dp[i][k] = min cost with exactly k matches in windows 0..i-1, last match at i-1
    # dp_none[k] = min cost with exactly k matches, no match window (sentinel: last match = -INF)

    # Use dp[last][k] where last is index of last match window (-1 means none)
    # Transition: last -> i (i > last), window i becomes a match

    # For windows between last+1 and i-1 (exclusive), they must not match.
    # Characters in window `last` (if last >= 0) are fixed to b.
    # Characters in window i are fixed to b.
    # For windows in between, we may need extra changes.

    # Precompute extra cost to ensure window w doesn't match,
    # given that characters from match windows are fixed.
    # This is complex; use a simpler bound: if window w already doesn't match after
    # fixing match windows, cost 0; else cost 1 (change one free character).

    # Simplified: precompute for each (p, i) pair the total cost
    def transition_cost(p, i):
        # p = previous match (-1 if none), i = current match
        # Check overlap feasibility
        if p >= 0 and i < p + m:
            overlap = p + m - i
            for j in range(overlap):
                if b[j + (i - p)] != b[j]:
                    return INF
        # Cost to make window i match (non-overlapping part)
        if p >= 0 and i < p + m:
            extra = sum(1 for j in range(p + m - i, m) if a[i + j] != b[j])
        else:
            extra = cost_match[i]
        # Cost to ensure windows p+1..i-1 don't match
        for w in range((p + 1) if p >= 0 else 0, i):
            # Check if window w matches after fixing chars from p and i
            already_no = False
            for j in range(m):
                pos = w + j
                fixed_val = None
                if p >= 0 and p <= pos < p + m:
                    fixed_val = b[pos - p]
                if i <= pos < i + m:
                    fv2 = b[pos - i]
                    if fixed_val is not None and fixed_val != fv2:
                        already_no = True; break
                    fixed_val = fv2
                if fixed_val is not None and fixed_val != b[j]:
                    already_no = True; break
            if not already_no:
                extra += 1
        return extra

    dp = [[INF] * (W + 1) for _ in range(W + 1)]
    # dp[i][k]: last match is window i, exactly k matches so far
    base = [INF] * (W + 1)
    base[0] = 0  # no matches yet, no last match (use index W as sentinel)

    for i in range(W):
        tc = transition_cost(-1, i)
        if tc < INF:
            dp[i][1] = min(dp[i][1], tc)

    for i in range(W):
        for k in range(1, W + 1):
            if dp[i][k] == INF:
                continue
            for j in range(i + 1, W):
                tc = transition_cost(i, j)
                if tc < INF:
                    if k + 1 <= W:
                        dp[j][k+1] = min(dp[j][k+1], dp[i][k] + tc)

    # For each k, find min over all last match positions, plus cost to ensure remaining windows don't match
    results = []
    for k in range(W + 1):
        if k == 0:
            # No matches: for each window, ensure it doesn't match
            cost = 0
            for w in range(W):
                if cost_match[w] == 0:
                    cost += 1
            results.append(cost)
            continue
        best = INF
        for last in range(W):
            if dp[last][k] == INF:
                continue
            # Ensure windows last+1..W-1 don't match
            extra = 0
            for w in range(last + 1, W):
                already_no = False
                for j in range(m):
                    pos = w + j
                    if last <= pos < last + m:
                        if b[pos - last] != b[j]:
                            already_no = True; break
                if not already_no:
                    extra += 1
            best = min(best, dp[last][k] + extra)
        results.append(best if best < INF else -1)

    print(*results)

solve()

